   239→    use super::*;
   240→
   241→    #[test]
   242→    fn test_primitive_send() {
   243→        // 모든 원시 타입은 Send여야 합니다.
   244→        // 이 함수들은 컴파일 타임에 검증되고,
   245→        // 컴파일 성공 = 테스트 통과
   246→        assert_send::<i32>();
   247→        assert_send::<f64>();
   248→        assert_send::<bool>();
   249→        assert_send::<str>();
