   255→        assert_sync::<i32>();
   256→        assert_sync::<f64>();
   257→        assert_sync::<bool>();
   258→        assert_sync::<str>();
   259→    }
   260→
   261→    #[test]
   262→    fn test_vec_send_with_send_element() {
