   291→    #[test]
   292→    fn test_arc_sync_with_send_sync_element() {
   293→        // Arc<i32>는 i32가 Send+Sync이므로 Sync여야 합니다.
   294→        assert_sync::<Arc<i32>>();
   295→    }
   296→
   297→    #[test]
   298→    fn test_mutex_send_with_send_element() {
   299→        // Mutex<i32>는 i32가 Send이므로 Send여야 합니다.
