    11→use crate::stdlib::FlValue;
    12→
    13→// ============================================================================
    14→// MathError - 수학 연산 에러 타입
    15→// ============================================================================
    16→
    17→/// 수학 연산 시 발생할 수 있는 에러
    18→#[derive(Clone, Debug, PartialEq)]
    19→pub enum MathError {
    20→    /// 0으로 나누기
    21→    DivideByZero,
    22→
    23→    /// 음수에 대한 제곱근
    24→    NegativeSqrt,
    25→
    26→    /// 범위 밖의 값 (예: log(0), asin(2))
    27→    DomainError(String),
    28→}
    29→
    30→impl std::fmt::Display for MathError {
    31→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    32→        match self {
    33→            MathError::DivideByZero => write!(f, "Division by zero"),
    34→            MathError::NegativeSqrt => write!(f, "Square root of negative number"),
    35→            MathError::DomainError(msg) => write!(f, "Domain error: {}", msg),
    36→        }
    37→    }
    38→}
    39→
    40→// ============================================================================
    41→// Basic Math Functions
    42→// ============================================================================
    43→
    44→/// 절댓값을 반환합니다.
    45→///
    46→/// # 예제
    47→/// ```
    48→/// assert_eq!(abs(FlValue::Int(-42)), FlValue::Int(42));
    49→/// assert_eq!(abs(FlValue::Float(-3.14)), FlValue::Float(3.14));
    50→/// ```
    51→pub fn abs(value: FlValue) -> Result<FlValue, MathError> {
    52→    match value {
    53→        FlValue::Int(n) => Ok(FlValue::Int(n.abs())),
    54→        FlValue::Float(f) => Ok(FlValue::Float(f.abs())),
    55→        _ => Err(MathError::DomainError("abs requires numeric value".to_string())),
    56→    }
    57→}
    58→
    59→/// 제곱근을 반환합니다.
    60→///
    61→/// # 에러
    62→/// - 음수: MathError::NegativeSqrt
    63→///
    64→/// # 예제
    65→/// ```
    66→/// assert_eq!(sqrt(FlValue::Int(4)), Ok(FlValue::Float(2.0)));
    67→/// assert_eq!(sqrt(FlValue::Float(2.0)), Ok(FlValue::Float(1.414...)));
    68→/// ```
    69→pub fn sqrt(value: FlValue) -> Result<FlValue, MathError> {
    70→    match value {
    71→        FlValue::Int(n) => {
    72→            if n < 0 {
    73→                Err(MathError::NegativeSqrt)
    74→            } else {
    75→                Ok(FlValue::Float((n as f64).sqrt()))
    76→            }
    77→        }
    78→        FlValue::Float(f) => {
    79→            if f < 0.0 {
    80→                Err(MathError::NegativeSqrt)
    81→            } else {
    82→                Ok(FlValue::Float(f.sqrt()))
    83→            }
    84→        }
    85→        _ => Err(MathError::DomainError("sqrt requires numeric value".to_string())),
    86→    }
    87→}
    88→
    89→/// 거듭제곱을 반환합니다 (base^exponent).
    90→///
    91→/// # 예제
    92→/// ```
    93→/// assert_eq!(pow(FlValue::Int(2), FlValue::Int(3)), Ok(FlValue::Float(8.0)));
    94→/// assert_eq!(pow(FlValue::Float(2.5), FlValue::Float(2.0)), Ok(FlValue::Float(6.25)));
    95→/// ```
    96→pub fn pow(base: FlValue, exponent: FlValue) -> Result<FlValue, MathError> {
    97→    let base_f = match base {
    98→        FlValue::Int(n) => n as f64,
    99→        FlValue::Float(f) => f,
   100→        _ => return Err(MathError::DomainError("pow base must be numeric".to_string())),
   101→    };
   102→
   103→    let exp_f = match exponent {
   104→        FlValue::Int(n) => n as f64,
   105→        FlValue::Float(f) => f,
   106→        _ => return Err(MathError::DomainError("pow exponent must be numeric".to_string())),
   107→    };
   108→
   109→    Ok(FlValue::Float(base_f.powf(exp_f)))
   110→}
   111→
   112→/// 내림(floor)을 반환합니다.
   113→///
   114→/// # 예제
   115→/// ```
   116→/// assert_eq!(floor(FlValue::Float(3.7)), FlValue::Int(3));
   117→/// assert_eq!(floor(FlValue::Float(-2.3)), FlValue::Int(-3));
   118→/// ```
   119→pub fn floor(value: FlValue) -> Result<FlValue, MathError> {
   120→    match value {
   121→        FlValue::Int(n) => Ok(FlValue::Int(n)),
   122→        FlValue::Float(f) => Ok(FlValue::Int(f.floor() as i64)),
   123→        _ => Err(MathError::DomainError("floor requires numeric value".to_string())),
   124→    }
   125→}
   126→
   127→/// 올림(ceiling)을 반환합니다.
   128→///
   129→/// # 예제
   130→/// ```
   131→/// assert_eq!(ceil(FlValue::Float(3.2)), FlValue::Int(4));
   132→/// assert_eq!(ceil(FlValue::Float(-2.8)), FlValue::Int(-2));
   133→/// ```
   134→pub fn ceil(value: FlValue) -> Result<FlValue, MathError> {
   135→    match value {
   136→        FlValue::Int(n) => Ok(FlValue::Int(n)),
   137→        FlValue::Float(f) => Ok(FlValue::Int(f.ceil() as i64)),
   138→        _ => Err(MathError::DomainError("ceil requires numeric value".to_string())),
   139→    }
   140→}
   141→
   142→/// 반올림을 반환합니다.
   143→///
