   400→pub fn min(a: FlValue, b: FlValue) -> Result<FlValue, MathError> {
   401→    match (a.clone(), b.clone()) {
   402→        (FlValue::Int(n1), FlValue::Int(n2)) => Ok(FlValue::Int(n1.min(n2))),
   403→        (FlValue::Float(f1), FlValue::Float(f2)) => Ok(FlValue::Float(f1.min(f2))),
