   405→            let f1 = n as f64;
   406→            Ok(FlValue::Float(f1.min(f)))
   407→        }
   408→        (FlValue::Float(f), FlValue::Int(n)) => {
   409→            let f2 = n as f64;
   410→            Ok(FlValue::Float(f.min(f2)))
   411→        }
   412→        _ => Err(MathError::DomainError("min requires numeric values".to_string())),
   413→    }
   414→}
