   438→/// 값을 범위 내로 제한합니다 (min <= n <= max).
   439→///
   440→/// # 예제
   441→/// ```
   442→/// assert_eq!(clamp(FlValue::Int(5), FlValue::Int(1), FlValue::Int(10)), FlValue::Int(5));
   443→/// assert_eq!(clamp(FlValue::Int(15), FlValue::Int(1), FlValue::Int(10)), FlValue::Int(10));
   444→/// assert_eq!(clamp(FlValue::Int(-5), FlValue::Int(1), FlValue::Int(10)), FlValue::Int(1));
   445→/// ```
   446→pub fn clamp(value: FlValue, min: FlValue, max: FlValue) -> Result<FlValue, MathError> {
   447→    match (value, min, max) {
   448→        (FlValue::Int(n), FlValue::Int(min_n), FlValue::Int(max_n)) => {
   449→            Ok(FlValue::Int(n.max(min_n).min(max_n)))
   450→        }
   451→        (FlValue::Float(f), FlValue::Float(min_f), FlValue::Float(max_f)) => {
   452→            Ok(FlValue::Float(f.max(min_f).min(max_f)))
   453→        }
   454→        _ => Err(MathError::DomainError("clamp requires numeric values".to_string())),
   455→    }
   456→}
